@SuppressWarnings('PMD.ClassNamingConventions')
public with sharing class ers_EncodeDecodeURL {
    /**
     * @description       Flow Action
     *
     * @param requestList
     * @return            `List<Results>`
     */
    @invocableMethod(
        label='URL Encode/Decode String'
        description='This Encodes or Decodes a string to handle spaces and other characters that are not allowed in urls'
    )
    public static List<Results> decodeStringForURL(List<Requests> requestList) {
        /* Prepare Response */
        Results response = new Results();
        List<Results> responseWrapper = new List<Results>();

        /* Process Inputs */
        for (Requests req : requestList) {
            /* Get Input Values */
            String inputStr = req.inputStr;
            String curEncoding = req.curEncoding;
            Boolean encode = req.encode;

            /* Perform Action(s) */
            if (!String.isBlank(inputStr)) {
                if (encode) {
                    response.outputStr = EncodingUtil.urlEncode(inputStr, curEncoding);
                } else {
                    response.outputStr = EncodingUtil.urlDecode(inputStr, curEncoding);
                }
            }

            /* Process Outputs */
            responseWrapper.add(response);
        }

        /* Return Results */
        return responseWrapper;
    }

    /**
     * Input parameters for the Apex action
     */
    public class Requests {
        @invocableVariable(label='Input String')
        public String inputStr;

        @invocableVariable(label='Encoding Method - Default: UTF-8')
        public String curEncoding = 'UTF-8';

        @invocableVariable(label='Encode? - Default: false(Decode)')
        public Boolean encode = false;
    }

    /**
     * Output parameters of the Apex actio
     */
    public class Results {
        @invocableVariable(label='Output String')
        public String outputStr;
    }
}

/**
 * @author Eric Smith
 * @group DataTable
 */
@SuppressWarnings('PMD.ClassNamingConventions')
@isTest
public with sharing class ers_EncodeDecodeURLTest {
    @isTest
    public static void testEncodeDecode() {
        string decoded = '2:{class: slds-theme_shade slds-theme_error}';
        string encoded = '2%3A%7Bclass%3A+slds-theme_shade+slds-theme_error%7D';

        ers_EncodeDecodeURL.Requests testRequest = new ers_EncodeDecodeURL.Requests();

        /* Decode */
        List<ers_EncodeDecodeURL.Requests> testDecodeRequestList = new List<ers_EncodeDecodeURL.Requests>();
        testRequest.inputStr = encoded;
        testDecodeRequestList.add(testRequest);
        List<ers_EncodeDecodeURL.Results> testDecodeResponseList = ers_EncodeDecodeURL.decodeStringForURL(
            testDecodeRequestList
        );
        System.assertEquals(decoded, testDecodeResponseList[0].outputStr);

        /* Encode */
        List<ers_EncodeDecodeURL.Requests> testEncodeRequestList = new List<ers_EncodeDecodeURL.Requests>();
        testRequest.inputStr = decoded;
        testRequest.encode = true;
        testEncodeRequestList.add(testRequest);
        List<ers_EncodeDecodeURL.Results> testEncodeResponseList = ers_EncodeDecodeURL.decodeStringForURL(
            testEncodeRequestList
        );
        System.assertEquals(encoded, testEncodeResponseList[0].outputStr);
    }
}

